"use client"

import Hero from "@/componenten/HomePage/Hero"
import Navbar from "@/componenten/HomePage/Navbar"
import Services from "@/componenten/HomePage/Services"
import { useEffect, useState, useRef } from "react"

export default function Home() {

  const [navState, setNavState] = useState<"transparent" | "gradient" | "white">("transparent")

  const heroRef = useRef<HTMLDivElement | null>(null)

  useEffect(() => {

    const handleScroll = () => {

      if (!heroRef.current) return

      const heroHeight = heroRef.current.offsetHeight
      const scroll = window.scrollY

      const oneThird = heroHeight / 3

      if (scroll < oneThird) {
        setNavState("transparent")
      }
      else if (scroll >= oneThird && scroll < heroHeight) {
        setNavState("gradient")
      }
      else {
        setNavState("white")
      }

    }

    window.addEventListener("scroll", handleScroll)

    return () => window.removeEventListener("scroll", handleScroll)

  }, [])

  return (

    <main className="bg-white">
      <Navbar navState={navState} />
      <div ref={heroRef}>
        <Hero />
      </div>
      <Services />
    </main>
  )
}